/**
 * Returns Office roaming settings when the host supports it.
 */
function getRoamingSettings() {
  const ctx = Office?.context;
  return ctx && ctx.roamingSettings ? ctx.roamingSettings : null;
}

/**
 * ตรวจสอบว่าอ็อบเจ็กต์เพย์โหลดมีรายการสิ่งอำนวยความสะดวกอย่างน้อยหนึ่งรายการหรือไม่
 */
function hasAmenitiesPayload(payload) {
  return Boolean(payload && typeof payload === "object" && Object.keys(payload).length > 0);
}

/**
 * อ่านค่า itemId จากรายการ Outlook ปัจจุบันและปรับให้เป็นค่ามาตรฐาน
 */
function extractInlineItemId(item) {
  if (!item || typeof item.itemId !== "string") return "";
  const itemId = item.itemId.trim();
  return itemId || "";
}

/**
 * ส่งคืนค่าจริงเมื่อรายการปัจจุบันมี itemId ที่บันทึกไว้แล้ว
 */
function hasSavedItemId(item) {
  return Boolean(extractInlineItemId(item));
}

/**
 * Gets a reliable saved itemId using inline value or getItemIdAsync fallback.
 */
function getSavedItemIdAsync(item) {
  const inlineId = extractInlineItemId(item);
  if (inlineId) return Promise.resolve(inlineId);
  if (!item || typeof item.getItemIdAsync !== "function") return Promise.resolve("");

  return new Promise((resolve) => {
    try {
      item.getItemIdAsync((res) => {
        if (res.status !== Office.AsyncResultStatus.Succeeded) return resolve("");
        if (typeof res.value !== "string") return resolve("");
        const id = res.value.trim();
        return resolve(id || "");
      });
    } catch (error) {
      return resolve("");
    }
  });
}

/**
 * Asynchronously checks whether the current item has a saved id.
 */
async function hasSavedItemIdAsync(item) {
  const id = await getSavedItemIdAsync(item);
  return Boolean(id);
}

/**
 * Parses JSON payload text and safely returns an amenities object.
 */
function parseAmenitiesPayload(raw, sourceLabel) {
  if (!raw || typeof raw !== "string") return {};

  try {
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === "object" ? parsed : {};
  } catch (error) {
    console.warn(`${sourceLabel} is not valid JSON:`, error);
    return {};
  }
}

/**
 * Normalizes text for matching by trimming and lowercasing.
 */
function normalizeText(value) {
  return String(value || "").trim().toLowerCase();
}
/**
 * Normalizes mailbox-like values (SMTP/mailto/email) into lowercase email.
 */
function normalizeMailboxAddress(value) {
  const raw = String(value || "").trim();
  if (!raw) return "";

  const protocolMatch = raw.match(/^(?:smtp:|mailto:)(.+)$/i);
  const withoutProtocol = protocolMatch && protocolMatch[1] ? protocolMatch[1].trim() : raw;
  const angleMatch = withoutProtocol.match(/<([^>]+)>/);
  const candidate = angleMatch && angleMatch[1] ? angleMatch[1].trim() : withoutProtocol;
  return candidate.includes("@") ? candidate.toLowerCase() : "";
}

